Component({
  properties: {
    type: {
      type: Number,
      value: 1
    },
    imgs: {
      type: Array,
      value: []
    }
  },
  methods: {
    clickImg(e) {
      const href = e.currentTarget.dataset.href
      if (!href) {
        return
      }
      this.triggerEvent('dealPath', {
        data: href
      })
    }
  }
})
